// Verifies §6.4 — auto-generated IDs do not get promoted to selector primary.
// Mirrors the regex set in content.js / spec §12.
const PATTERNS = [
  /^mui-/, /^emotion-/, /^radix-/, /^chakra-/, /^css-/,
  /^MuiBox-/, /^sc-/,
  /^:r[0-9a-z]+:$/,
  /^[a-z0-9]{6,}-[a-z0-9]{6,}$/
];

function isAutoGeneratedId(id) {
  if (!id) return true;
  return PATTERNS.some(rx => rx.test(id));
}

const reject = [
  'mui-3-input-7', 'emotion-1', 'radix-foo', 'chakra-bar', 'css-9k',
  'MuiBox-root', 'sc-abc', ':r3a:', 'a1b2c3-d4e5f6'
];
const accept = [
  'submit-btn', 'login', 'email', 'mainContent', 'pw'
];

let ok = true;
for (const id of reject) {
  if (!isAutoGeneratedId(id)) { console.error('FAIL: should reject', id); ok = false; }
  else console.log('OK  reject', id);
}
for (const id of accept) {
  if (isAutoGeneratedId(id)) { console.error('FAIL: should accept', id); ok = false; }
  else console.log('OK  accept', id);
}
process.exit(ok ? 0 : 1);
